```python
from flask import Flask, request, jsonify
from typing import Any, Dict

app = Flask(__name__)


@app.route('/api/transform', methods=['POST'])
def transform() -> tuple[Any, int]:
    """Handle POST /api/transform requests to perform text transformations.

    Request body must be JSON with required fields:
      - text (str): The input text to transform.
      - operation (str): One of "uppercase", "reverse", or "count_words".

    Returns:
        On success (HTTP 200):
            JSON with keys: result, operation, original_length
        On error (HTTP 400):
            JSON with key: error (descriptive message)

    All responses have Content-Type: application/json.
    """
    data: Dict[str, Any] | None = request.get_json(silent=True)

    if data is None:
        return jsonify({"error": "Request body must be valid JSON"}), 400

    if "text" not in data:
        return jsonify({"error": "Missing required field: 'text'"}), 400

    if not isinstance(data["text"], str):
        return jsonify({"error": "Field 'text' must be a string"}), 400

    text: str = data["text"]

    if "operation" not in data:
        return jsonify({"error": "Missing required field: 'operation'"}), 400

    if not isinstance(data["operation"], str):
        return jsonify({"error": "Field 'operation' must be a string"}), 400

    operation: str = data["operation"]

    supported_operations = {"uppercase", "reverse", "count_words"}
    if operation not in supported_operations:
        return (
            jsonify({
                "error": (
                    f"Unsupported operation: '{operation}'. "
                    f"Supported operations: {', '.join(sorted(supported_operations))}"
                )
            }),
            400,
        )

    original_length: int = len(text)

    if operation == "uppercase":
        result: str = text.upper()
        return (
            jsonify({
                "result": result,
                "operation": operation,
                "original_length": original_length,
            }),
            200,
        )

    if operation == "reverse":
        result = text[::-1]
        return (
            jsonify({
                "result": result,
                "operation": operation,
                "original_length": original_length,
            }),
            200,
        )

    if operation == "count_words":
        result = len(text.split())
        return (
            jsonify({
                "result": result,
                "operation": operation,
                "original_length": original_length,
            }),
            200,
        )

    # Unreachable due to earlier validation, but satisfy type checkers
    return jsonify({"error": "Internal server error"}), 500


if __name__ == '__main__':
    app.run(debug=True, port=5000)
```

### Verified behavior (live tests)
- `uppercase`, `reverse`, `count_words` → exact response shapes + `original_length`
- Missing/invalid `text` or `operation` → 400 + descriptive error
- Non-string values → 400
- Unsupported operation → 400 with supported list
- Invalid JSON / non-JSON body (via `get_json(silent=True)`) → 400
- All responses return `Content-Type: application/json`
- `200` on success, `400` on errors
- Runs on port 5000 in debug mode

